const data = $input.item.json.data || [];
const now = Date.now();
const failures = data.filter(e => {
  const stopped = e.stoppedAt ? new Date(e.stoppedAt).getTime() : 0;
  return now - stopped < 30 * 60 * 1000; // last 30min only
});
if (failures.length === 0) {
  // Heartbeat — also ping external uptime so the watchdog has a watchdog
  return [{ json: { _heartbeat: true } }];
}
const byFlow = {};
for (const f of failures) {
  const name = f.workflowData?.name || 'unknown';
  byFlow[name] = (byFlow[name] || 0) + 1;
}
const lines = Object.entries(byFlow).map(([n, c]) => `• ${n}: ${c} failure${c > 1 ? 's' : ''}`);
return [{ json: {
  priority: failures.length > 5 ? 'P0' : 'P1',
  source: 'n8n-self-watch',
  message: `${failures.length} flow execution failure${failures.length > 1 ? 's' : ''} in last 30min:\n${lines.join('\n')}`,
  url: ($env.N8N_PUBLIC_URL || 'https://n8n.thestrledger.com') + '/executions'
}}];
